from __future__ import annotations
from typing import Any


def build_answers(ctx: dict[str, Any]) -> dict[str, str]:
    return {'forecast_volume': f"The selected {ctx['selected_forecast']} model forecasts about {ctx['forecast_total']:,.0f} referrals over 12 weeks, approximately {ctx['forecast_total'] / len(ctx['forecast']):.1f} per week.", 'forecast_uncertainty': f"The 12-week synthetic planning range sums to roughly {ctx['forecast_low']:,.0f}–{ctx['forecast_high']:,.0f} referrals around a P50 of {ctx['forecast_total']:,.0f}. Backtest WAPE is {ctx['_pct'](ctx['selected_performance']['mean_wape'])} and under-forecast rate {ctx['_pct'](ctx['selected_performance']['mean_underforecast_rate'])}.", 'structural_change': f"There are {ctx['anomaly_count']} amber/red weekly anomaly flags. These request investigation of source changes, policy, seasonality and workflow; they do not by themselves prove a structural break.", 'budget_plan': f"Under the synthetic £10,000 budget, {ctx['budget_10k']['plan_id']} adds {int(ctx['budget_10k']['extra_assessment_minutes_per_week'])} assessment minutes/week and {int(ctx['budget_10k']['outreach_contacts_per_week'])} outreach contacts/week, ending at {ctx['_fmt'](ctx['budget_10k']['end_backlog'], 0)} backlog patients.", 'assumption_sensitivity': 'The current recommendation depends on cost proxies, appointment duration and assumed reminder effect. I would rerun a grid of real finance-approved unit costs and plausible effect bounds and report where the preferred plan changes.', 'stress_scenario': f"A 10% demand increase ends at {ctx['_fmt'](ctx['demand_up']['end_backlog'], 0)} backlog patients, while 10% clinician absence ends at {ctx['_fmt'](ctx['absence']['end_backlog'], 0)}, versus {ctx['_fmt'](ctx['baseline_scenario']['end_backlog'], 0)} at baseline."}
